        suffixT[i] = suffixT[i + 1] + (s[i] === 'T' ? 1 : 0);
    }

    // Calculate the best position to insert 'L'
    let bestInsertL = 0;
    for (let i = 0; i <= n; i++) {
        const additional = suffixC[i] * suffixT[i];
        bestInsertL = Math.max(bestInsertL, tCount + additional);
