    for (let i = 0; i <= n; i++) {
        const lBefore = prefixLForC[i];
        const tAfter = suffixT[i];
        const additional = lBefore * tAfter;
        bestInsertC = Math.max(bestInsertC, tCount + additional);
    }

    // Calculate the best position to insert 'T'
    let bestInsertT = 0;
    const prefixCForT = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
