        bestInsertT = Math.max(bestInsertT, tCount + cBefore);
    }

    // The maximum possible is the best among inserting 'L', 'C', 'T' or not inserting anything
    maxLCT = Math.max(maxLCT, bestInsertL, bestInsertC, bestInsertT);

    return maxLCT;
}
